@startuml
skinparam classAttributeIconSize 0
skinparam shadowing false
skinparam linetype ortho

class Context {
  - Strategy strategy
  + setStrategy(Strategy strategy)
  + execMethod()
}

interface Strategy {
  + method()
}

class StrategyImp2 {
  + method()
}

class StrategyImp1 {
  + method()
}

Context o-- Strategy

StrategyImp2 ..|> Strategy
StrategyImp1 ..|> Strategy

note left of Context
public void execMethod() {
    strategy.method();
}
end note

@enduml
